// 1. Obter todas as marcas encontradas pelo banco de dados
const marcasEncontradas = $input.all().map(item => item.json.nome).filter(Boolean);

// 2. Tentar obter a marca monitorada usando variações comuns de chaves
const noOriginal = $('Set').first().json;
const marcaMonitorada = noOriginal.marca_monitorada || noOriginal.brand || noOriginal.marca || "";
const textoOriginal = noOriginal.texto || noOriginal.text || "";

// 3. Normalizar para comparação case-insensitive
const marcaMonitoradaLower = marcaMonitorada.toLowerCase().trim();

// 4. Verificar se a marca monitorada foi encontrada pelo banco
const indexEncontrado = marcasEncontradas.findIndex(m => m.toLowerCase().trim() === marcaMonitoradaLower);
const ownBrandMentioned = indexEncontrado !== -1;
const ownBrandCorrected = ownBrandMentioned ? marcasEncontradas[indexEncontrado] : null;

// 5. Filtrar as outras marcas (concorrentes)
const otherBrands = marcasEncontradas.filter(m => m.toLowerCase().trim() !== marcaMonitoradaLower);

// 6. Decidir se precisa de fallback (Gemini)
const needsFallback = !ownBrandMentioned;

return [{
  json: {
    own_brand_mentioned: ownBrandMentioned,
    own_brand_corrected: ownBrandCorrected,
    other_brands: otherBrands,
    needs_fallback: needsFallback,
    original_text: textoOriginal,
    original_brand: marcaMonitorada
  }
}];

// 1. Tenta pegar a resposta do GPT (pode vir no campo 'text' ou 'message.content' no n8n)
const rawText = $input.first().json.text || $input.first().json.message?.content || "";

// 2. Faz o parse do texto para transformá-lo em JSON
const gptObj = JSON.parse(rawText.trim());

// 3. Retorna apenas as duas informações exigidas no teste
return [{
  json: {
    own_brand_mentioned: gptObj.own_brand_mentioned,
    other_brands: gptObj.other_brands
  }
}];
